    precision >= minimums.precision_at_k &&
    recall >= minimums.recall_at_k &&
    mrr >= minimums.mrr_at_k &&
    ndcg >= minimums.ndcg_at_k &&
    gradeRecall >= minimums.grade_recall_at_k;

  return {
    precision_at_k: precision,
    recall_at_k: recall,
    mrr_at_k: mrr,
