export type EdgeKind =
  | "about"
  | "contains"
  | "touches"
  | "supersedes"
  | "evidenced_by";

export type EdgeMetadata = Record<string, unknown>;

export interface Edge {
  id: EdgeId;
  from_id: string;
  from_type: GraphObjectType;
  to_id: string;
